// Verify Bland AI webhook signature
const crypto = require('crypto');

const headers = $input.first().json.headers;
const body = $input.first().json.body;
const signature = headers['x-bland-signature'];

// Get secret from n8n environment variable
const secret = $env.BLAND_WEBHOOK_SECRET;

if (secret && signature) {
  const expectedSignature = crypto
    .createHmac('sha256', secret)
    .update(JSON.stringify(body))
    .digest('hex');

  if (signature !== expectedSignature) {
    throw new Error('Invalid Bland AI webhook signature');
  }
}

// Extract and flatten the data
const data = body;
return [{
  json: {
    call_id: data.call_id,
    status: data.status || (data.completed ? 'completed' : 'failed'),
    completed: data.completed,
    call_length: data.call_length,
    to: data.to,
    from: data.from,
    answered_by: data.answered_by,
    recording_url: data.recording_url,
    transcript: data.concatenated_transcript,
    summary: data.summary,
    error_message: data.error_message,
    price: data.price,
    metadata: data.metadata || {},
    company_id: data.metadata?.company_id,
    contact_id: data.metadata?.contact_id,
    agent_type: data.metadata?.agent_type || 'general',
    agent_run_id: data.metadata?.agent_run_id,
    agent_name: data.metadata?.agent_name,
    raw: data
  }
}];

// Prepare OpenAI prompt based on agent type
const item = $input.first().json;
const agentType = item.agent_type;
const transcript = item.transcript || '';
const contactName = item.metadata?.contact_name || 'the contact';

const systemPrompts = {
  'appointment-confirmation': `You analyze phone call transcripts where an AI agent confirmed an appointment with ${contactName}. Return JSON with: confirmed (boolean), needs_reschedule (boolean), new_datetime (ISO string or null), no_show_risk (low/medium/high), sentiment (positive/neutral/negative), key_notes (string).`,
  'lead-qualification': `You analyze phone call transcripts where an AI agent qualified ${contactName} as a sales lead. Return JSON with BANT scores: budget (1-10), authority (1-10), need (1-10), timeline (1-10), overall_score (1-100), qualification (hot/warm/cold), interested_products (array), next_action (string), key_notes (string).`,
  'data-validation': `You analyze phone call transcripts where an AI agent verified contact information for ${contactName}. Return JSON with: verified_fields (object with email/phone/address/job_title each having value and verified boolean), corrections (array of {field, old_value, new_value}), confidence (high/medium/low), key_notes (string).`
};

const systemPrompt = systemPrompts[agentType] || systemPrompts['lead-qualification'];

return [{
  json: {
    ...item,
    system_prompt: systemPrompt,
    user_message: `Analyze this call transcript and respond with valid JSON only:\n\n${transcript}`
  }
}];

// Merge AI analysis back with call data
const callData = $('Prepare AI Prompt').first().json;
let aiAnalysis = {};

try {
  const aiResponse = $input.first().json.message?.content || $input.first().json.text || '{}';
  aiAnalysis = typeof aiResponse === 'string' ? JSON.parse(aiResponse) : aiResponse;
} catch (e) {
  aiAnalysis = { error: 'Failed to parse AI response', raw: $input.first().json };
}

return [{
  json: {
    ...callData,
    ai_analysis: aiAnalysis,
    analyzed_at: new Date().toISOString()
  }
}];

// Handle appointment confirmation results
const item = $input.first().json;
const analysis = item.ai_analysis || {};

const result = {
  action: 'none',
  event_type: 'call.completed',
  ...item
};

if (analysis.confirmed) {
  result.action = 'confirm';
  result.event_type = 'appointment.confirmed';
} else if (analysis.needs_reschedule && analysis.new_datetime) {
  result.action = 'reschedule';
  result.event_type = 'appointment.rescheduled';
  result.new_datetime = analysis.new_datetime;
} else if (analysis.no_show_risk === 'high') {
  result.action = 'flag_no_show';
  result.event_type = 'appointment.no_show';
}

result.slack_message = `*Appointment ${result.action}* for ${item.metadata?.contact_name || 'contact'}\n` +
  `Sentiment: ${analysis.sentiment || 'unknown'}\n` +
  `Notes: ${analysis.key_notes || 'none'}`;

return [{ json: result }];

// Handle lead qualification results
const item = $input.first().json;
const analysis = item.ai_analysis || {};

const result = {
  action: 'scored',
  qualification: analysis.qualification || 'cold',
  overall_score: analysis.overall_score || 0,
  event_type: 'call.completed',
  ...item
};

if (analysis.qualification === 'hot' && analysis.overall_score >= 80) {
  result.action = 'schedule_meeting';
  result.event_type = 'appointment.scheduled';
}

result.slack_message = `*Lead Scored: ${analysis.qualification?.toUpperCase() || 'UNKNOWN'}* (${analysis.overall_score || 0}/100)\n` +
  `Contact: ${item.metadata?.contact_name || 'unknown'}\n` +
  `BANT: B:${analysis.budget || 0} A:${analysis.authority || 0} N:${analysis.need || 0} T:${analysis.timeline || 0}\n` +
  `Next: ${analysis.next_action || 'none'}`;

return [{ json: result }];

// Handle data validation results
const item = $input.first().json;
const analysis = item.ai_analysis || {};

const result = {
  action: 'validated',
  event_type: 'contact.updated',
  ...item
};

const verifiedCount = Object.values(analysis.verified_fields || {}).filter(f => f.verified).length;
const totalFields = Object.keys(analysis.verified_fields || {}).length;

result.slack_message = `*Data Validated* for ${item.metadata?.contact_name || 'contact'}\n` +
  `Verified: ${verifiedCount}/${totalFields} fields\n` +
  `Confidence: ${analysis.confidence || 'unknown'}\n` +
  `Corrections: ${(analysis.corrections || []).length}`;

return [{ json: result }];

// Dispatch to user-configured webhook endpoints
const item = $input.first().json;
const crypto = require('crypto');

// This will be replaced with actual webhook endpoint queries
// For now, prepare the webhook payload
const timestamp = Math.floor(Date.now() / 1000);
const payload = {
  event: item.event_type || 'call.completed',
  timestamp: timestamp,
  data: {
    call_id: item.call_id,
    contact_id: item.contact_id,
    company_id: item.company_id,
    agent_type: item.agent_type,
    status: item.status,
    duration: item.call_length,
    ai_analysis: item.ai_analysis,
    recording_url: item.recording_url
  }
};

return [{
  json: {
    ...item,
    webhook_payload: payload
  }
}];

// Log missed call and schedule retry
const item = $input.first().json;

return [{
  json: {
    ...item,
    status: item.answered_by === 'voicemail' ? 'voicemail' : 'no_answer',
    event_type: item.answered_by === 'voicemail' ? 'call.voicemail' : 'call.no_answer',
    should_retry: true,
    slack_message: `*Missed Call* to ${item.metadata?.contact_name || item.to}\n` +
      `Result: ${item.answered_by || 'no answer'}\n` +
      `Will retry automatically.`
  }
}];
